func obtainCredentials(xpanID: Data) async -> (cred: THCredentials? ,err: Error? ) {
    let client = THClient()
    var credential: THCredentials?
    var err:Error?
    do {
        credential = try await client.credentials(forExtendedPANID: xpanID as Data)
    } catch {
        err = error
    }
    return (credential, err)
}
